import HomeBanner from "../../Components/Header/HomeBanner";

const Home = () => {
  return (
    <>
      <HomeBanner />
      <section className="homeProducts">
        <div className="container">
          <div className="row">
            <div className="col-md-3">
              <img src="" />
            </div>
          </div>
        </div>
      </section>
    </>
  );
};
export default Home;
